def solve(n, logs):
    res = [0] * n
    stack = []
    for log in logs:
        parts = log.split(':')
        fn = int(parts[0])
        typ = parts[1]
        time = int(parts[2])
        if typ == 'start':
            if stack:
                res[stack[-1]] += time
            stack.append(fn)
            res[fn] -= time
        else:
            res[stack.pop()] += time + 1
            if stack:
                res[stack[-1]] -= time + 1
    return str(res).replace("'", '"')
